using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: EF Core 9 renamed the discriminator property from
        // "Discriminator" to "$type". Restore the old name for existing documents.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change: EF Core 9 changed the default id format from
        // "EntityType|Key" to just the key value. Restore the old format
        // for existing documents with ids like "Blog|1".
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>(b =>
        {
            b.Property(x => x.Id)
             .ToJsonProperty("id")
             .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.Internal.IdValueGenerator>();
        });

        // Breaking change: HasIndex now throws on Cosmos instead of being
        // silently ignored. Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        base.OnConfiguring(optionsBuilder);
        // Breaking change: EF Core 9 Cosmos provider no longer supports
        // synchronous I/O by default. If async migration isn't possible
        // everywhere yet, opt in explicitly.
    }
}
