        // Breaking change 2: EF Core 9 changed the default id format from
        // "EntityType|Key" (e.g. "Blog|1") to just the raw key value.
        // Use a value converter so existing documents with the old format
        // are read/written correctly.
        modelBuilder.Entity<Blog>()
            .Property(b => b.Id)
            .HasConversion(
                id => $"Blog|{id}",
