        // Breaking change 3: HasIndex now throws on Cosmos instead of being
        // silently ignored. Removed the following line:
        //   modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

